<?php
namespace Tests\Feature;use App\Models\{Permission,PermissionAuditLog,User,UserPermission};use Database\Seeders\PermissionsSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class DatabasePermissionsTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(PermissionsSeeder::class);}private function user(string $role):User{return User::create(['name'=>$role,'email'=>uniqid()."@$role.test",'password'=>'Password123!','role'=>$role,'is_active'=>true]);}
public function test_role_defaults():void{$admin=$this->user('admin');$tech=$this->user('technician');$accountant=$this->user('accountant');$custom=$this->user('custom');$this->assertCount(Permission::count(),$admin->getEffectivePermissions());$this->assertTrue($tech->hasPermission('job_cards.edit'));$this->assertFalse($tech->hasPermission('users.view'));$this->assertTrue($accountant->hasPermission('invoices.process'));$this->assertFalse($accountant->hasPermission('services.complete'));$this->assertSame([],$custom->getEffectivePermissions());}
public function test_explicit_allow_and_deny_and_peer_isolation():void{$a=$this->user('technician');$b=$this->user('technician');$edit=Permission::where('key','job_cards.edit')->first();$users=Permission::where('key','users.view')->first();UserPermission::create(['user_id'=>$a->id,'permission_id'=>$edit->id,'allowed'=>false]);UserPermission::create(['user_id'=>$a->id,'permission_id'=>$users->id,'allowed'=>true]);$this->assertFalse($a->hasPermission('job_cards.edit'));$this->assertTrue($a->hasPermission('users.view'));$this->assertTrue($b->hasPermission('job_cards.edit'));$this->assertFalse($b->hasPermission('users.view'));}
public function test_api_denial_audit_and_final_admin_safeguard():void{$admin=$this->user('admin');$tech=$this->user('technician');$this->actingAs($tech)->getJson('/api/permissions')->assertForbidden();$this->actingAs($admin)->putJson("/api/users/$tech->id/permissions",['permissions'=>[['key'=>'clients.delete','allowed'=>true]]])->assertOk();$this->assertDatabaseHas('permission_audit_logs',['affected_user_id'=>$tech->id,'permission_key'=>'clients.delete','action'=>'permission.changed']);$this->actingAs($admin)->putJson("/api/users/$admin->id/permissions",['permissions'=>[['key'=>'users.permissions.manage','allowed'=>false],['key'=>'users.roles.manage','allowed'=>true]]])->assertStatus(422);$this->assertTrue($admin->fresh()->hasPermission('users.permissions.manage'));$this->actingAs($admin)->putJson("/api/users/$admin->id/role",['role'=>'technician'])->assertStatus(422);$this->assertSame('admin',$admin->fresh()->role);}
}
